#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, L, X; scanf("%lld %lld %lld", &N, &L, &X);
        long long right = N - L;
        long long pairs = L < right ? L : right;
        long long ans = pairs * X;
        printf("%lld\n", ans);
    }
    return 0;
}

